from dataclasses import dataclass
from heapq import heappush, heappop

DIRS = {'north':(-1,0),'south':(1,0),'west':(0,-1),'east':(0,1)}
ORIENTS = ['N','E','S','W']
CW = {'N':'E','E':'S','S':'W','W':'N'}
CCW = {'N':'W','W':'S','S':'E','E':'N'}
DIAL_POS = {'alpha':(6,2),'beta':(3,3),'gamma':(1,2),'delta':(3,1)}
DIAL_CONVEYOR = {'alpha':(5,4),'beta':(3,4),'gamma':(1,3),'delta':(3,1)}
TARGETS = {'alpha':'E','beta':'W','gamma':'S','delta':'N'}
AMBER_RESET=(5,1)
JADE_RESET=(1,4)
AMBER_PLATE=(5,5)
JADE_PLATE=(3,3)
GATE_A=(4,4)
GATE_B=(4,2)
RESET=(3,4)
RELIQ=(6,6)
ICE={(5,2),(5,3),(2,4)}
BASE_PASSABLE={(0,3),(0,4),(0,5),(1,2),(1,3),(1,4),(1,5),(2,1),(2,2),(2,3),(2,4),(2,5),(3,1),(3,2),(3,3),(3,4),(3,5),(5,0),(5,1),(5,2),(5,3),(5,4),(5,5),(6,0),(6,1),(6,2),(6,3),(6,4),(6,5),(6,6)}
SEAL_EXPECT = ['clockwise','counterclockwise','counterclockwise','clockwise']

# sorted full command vocabulary for lexicographic tie-breaking
VOCAB = sorted([
    'drop sun',
    'move east','move north','move south','move west',
    'push amber east','push amber west','push jade north','push jade south',
    'take sun',
    'turn alpha clockwise','turn alpha counterclockwise',
    'turn beta clockwise','turn beta counterclockwise',
    'turn delta clockwise','turn delta counterclockwise',
    'turn gamma clockwise','turn gamma counterclockwise',
    'turn seal clockwise','turn seal counterclockwise',
    'use reset shrine','use sun reliquary',
    'wait',
])
VIDX = {c:i for i,c in enumerate(VOCAB)}

@dataclass(frozen=True)
class State:
    player: tuple
    amber: tuple
    jade: tuple
    alpha: str
    beta: str
    gamma: str
    delta: str
    b_open: bool
    sun_mode: str  # 'ground','inv','used'
    sun_pos: tuple
    reset_spent: bool
    seal_armed: bool
    seal_progress: int

    def dials(self):
        return {'alpha':self.alpha,'beta':self.beta,'gamma':self.gamma,'delta':self.delta}

init = State((6,0),(5,1),(2,1),'N','N','W','E',False,'ground',(2,5),False,False,0)

def gate_a_open(s):
    return s.amber == AMBER_PLATE

def is_passable_cell(s, pos):
    if pos in BASE_PASSABLE:
        return True
    if pos == GATE_A:
        return gate_a_open(s)
    if pos == GATE_B:
        return s.b_open
    return False

def occupied_by_crate(s, pos):
    return pos == s.amber or pos == s.jade

def player_can_enter(s, pos):
    return is_passable_cell(s, pos) and not occupied_by_crate(s, pos)

def crate_can_enter(s, pos, crate_name):
    if not is_passable_cell(s, pos):
        return False
    other = s.jade if crate_name == 'amber' else s.amber
    return pos != other and pos != s.player

def slide_from(s, start, direction, mover):
    # start is already entered and must be passable/empty per mover rules
    cur = start
    dr, dc = DIRS[direction]
    while cur in ICE:
        nxt = (cur[0]+dr, cur[1]+dc)
        if mover == 'player':
            if not player_can_enter(s, nxt):
                break
        else:
            if not crate_can_enter(s, nxt, mover):
                break
        cur = nxt
    return cur

def conveyor_dir(s, pos):
    if pos == DIAL_CONVEYOR['alpha']:
        return s.alpha
    if pos == DIAL_CONVEYOR['beta']:
        return s.beta
    if pos == DIAL_CONVEYOR['gamma']:
        return s.gamma
    if pos == DIAL_CONVEYOR['delta']:
        return s.delta
    return None

def try_conveyor_move(s, crate_name, pos, amber_pos, jade_pos):
    cdir = conveyor_dir(s, pos)
    if not cdir:
        return pos
    drdc = {'N':(-1,0),'S':(1,0),'W':(0,-1),'E':(0,1)}[cdir]
    nxt = (pos[0]+drdc[0], pos[1]+drdc[1])
    other = jade_pos if crate_name == 'amber' else amber_pos
    if nxt == other or nxt == s.player:
        return pos
    # construct temporary state predicate for passability only
    if nxt in BASE_PASSABLE or (nxt == GATE_A and gate_a_open(s)) or (nxt == GATE_B and s.b_open):
        return nxt
    return pos

def apply_conveyors(s):
    amber, jade = s.amber, s.jade
    # simultaneous from start positions, blocked by start occupancy / player.
    amber_target = try_conveyor_move(s, 'amber', amber, amber, jade)
    jade_target = try_conveyor_move(s, 'jade', jade, amber, jade)
    if amber_target == jade_target and amber_target != amber and jade_target != jade:
        # conservative collision rule: both stay.
        amber_target, jade_target = amber, jade
    elif amber_target == jade and jade_target == jade:
        amber_target = amber
    elif jade_target == amber and amber_target == amber:
        jade_target = jade
    return amber_target, jade_target

def turn_dir(o, t):
    return CW[o] if t == 'clockwise' else CCW[o]

def legal_and_next(s, cmd):
    words = cmd.split()
    irrevers = 0
    pushes = 0
    player, amber, jade = s.player, s.amber, s.jade
    alpha,beta,gamma,delta = s.alpha,s.beta,s.gamma,s.delta
    b_open = s.b_open
    sun_mode, sun_pos = s.sun_mode, s.sun_pos
    reset_spent = s.reset_spent
    seal_armed = s.seal_armed
    seal_progress = s.seal_progress

    moved = None
    # validate + primary action
    if words[0] == 'move':
        d = words[1]
        dr,dc = DIRS[d]
        nxt = (player[0]+dr, player[1]+dc)
        if not player_can_enter(s, nxt):
            return None
        player = slide_from(s, nxt, d, 'player')
    elif words[0] == 'push':
        crate = words[1]
        d = words[2]
        if crate == 'amber' and d not in ('east','west'):
            return None
        if crate == 'jade' and d not in ('north','south'):
            return None
        dr,dc = DIRS[d]
        cpos = amber if crate == 'amber' else jade
        behind = (cpos[0]-dr, cpos[1]-dc)
        if player != behind:
            return None
        nxt = (cpos[0]+dr, cpos[1]+dc)
        if not crate_can_enter(s, nxt, crate):
            return None
        end = slide_from(s, nxt, d, crate)
        if crate == 'amber':
            amber = end
        else:
            jade = end
        pushes = 1
        irrevers = 1
    elif words[0] == 'turn':
        target = words[1]
        tdir = words[2]
        if target == 'seal':
            if not seal_armed:
                return None
            if abs(player[0]-RELIQ[0]) + abs(player[1]-RELIQ[1]) > 1:
                return None
            if tdir == SEAL_EXPECT[seal_progress]:
                seal_progress += 1
            else:
                seal_progress = 0
        else:
            dpos = DIAL_POS[target]
            if abs(player[0]-dpos[0]) + abs(player[1]-dpos[1]) > 1:
                return None
            if target == 'alpha': alpha = turn_dir(alpha, tdir)
            elif target == 'beta': beta = turn_dir(beta, tdir)
            elif target == 'gamma': gamma = turn_dir(gamma, tdir)
            elif target == 'delta': delta = turn_dir(delta, tdir)
    elif words[0] == 'take':
        item = words[1]
        if item != 'sun' or sun_mode != 'ground' or player != sun_pos:
            return None
        # item phase later
    elif words[0] == 'drop':
        item = words[1]
        if item != 'sun' or sun_mode != 'inv':
            return None
    elif words[0] == 'use':
        if words[1] == 'reset':
            if player != RESET or reset_spent:
                return None
            amber = AMBER_RESET
            jade = JADE_RESET
            reset_spent = True
            seal_progress = 0
            irrevers = 1
        elif words[1] == 'sun':
            if player != RELIQ or sun_mode != 'inv' or not reset_spent:
                return None
            if not (alpha == TARGETS['alpha'] and beta == TARGETS['beta'] and gamma == TARGETS['gamma'] and delta == TARGETS['delta']):
                return None
            # consume at item phase; arm now/at end equivalent here
            seal_armed = True
            sun_mode = 'used'
            sun_pos = (-1,-1)
            irrevers = 1
        else:
            return None
    elif words[0] == 'wait':
        pass
    else:
        return None

    tmp = State(player, amber, jade, alpha, beta, gamma, delta, b_open, sun_mode, sun_pos, reset_spent, seal_armed, seal_progress)

    # phase 4 conveyors
    amber, jade = apply_conveyors(tmp)

    # phase 5 plates / 6 gates
    if jade == JADE_PLATE:
        b_open = True

    # phase 7 item actions
    if words[0] == 'take':
        sun_mode = 'inv'
        sun_pos = (-1,-1)
    elif words[0] == 'drop':
        sun_mode = 'ground'
        sun_pos = player
    # use sun already consumed; use reset already applied

    ns = State(player, amber, jade, alpha, beta, gamma, delta, b_open, sun_mode, sun_pos, reset_spent, seal_armed, seal_progress)
    solved = seal_armed and seal_progress >= 4
    return ns, pushes, irrevers, solved

# quick check explorer transcript in model
explorer = [
    'move east', 'turn alpha clockwise', 'move west', 'move north', 'push amber east',
    'move east', 'move east', 'move north', 'move north', 'turn beta counterclockwise',
    'use reset shrine', 'move east', 'move north', 'take sun', 'move north', 'move north',
