# dijkstra on (commands, pushes, irreversible, lex transcript)
start = init
best = {start: (0,0,0,())}
pq = [(0,0,0,(), start)]
visited = 0
best_solution = None
while pq:
    cost_cmds, cost_push, cost_irr, seq, state = heappop(pq)
    if best[state] != (cost_cmds, cost_push, cost_irr, seq):
        continue
    visited += 1
    # no need extra solved flag in state; any state may be solved by progress>=4 & armed
    if state.seal_armed and state.seal_progress >= 4:
        best_solution = (cost_cmds, cost_push, cost_irr, seq)
        break
    # prune if already worse than best solution numerically
    if best_solution and (cost_cmds, cost_push, cost_irr) > best_solution[:3]:
        continue
    # generate all commands in lex order, filter legal
    for cmd in VOCAB:
