        if r is None:
            continue
        ns, p_inc, i_inc, solved = r
        ncost = (cost_cmds+1, cost_push+p_inc, cost_irr+i_inc, seq + (VIDX[cmd],))
        old = best.get(ns)
        if old is None or ncost < old:
            best[ns] = ncost
            heappush(pq, (*ncost, ns))

print('visited', visited, 'states', len(best))
if best_solution:
    cmds = [VOCAB[i] for i in best_solution[3]]
    print('solution metrics', best_solution[:3])
    print('commands:')
    for c in cmds:
        print(c)
else:
    print('no solution')
